1	export type Cell = [x: number, y: number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const offsets = [-1, 0, 1];
7	  const result: Cell[] = [];
8	  for (const dx of offsets) {
9	    for (const dy of offsets) {
10	      if (dx === 0 && dy === 0) continue;
11	      result.push([x + dx, y + dy]);
12	    }
13	  }
14	  return result;
15	};
16	
17	const countLiveNeighbors = (cells: Cell[]): Map<string, { cell: Cell; count: number }> => {
18	  const counts = new Map<string, { cell: Cell; count: number }>();
19	  for (const cell of cells) {
20	    for (const neighbor of neighborsOf(cell)) {
21	      const key = cellKey(neighbor);
22	      const existing = counts.get(key);
23	      if (existing) existing.count += 1;
24	      else counts.set(key, { cell: neighbor, count: 1 });
25	    }
26	  }
27	  return counts;
28	};
29	
30	const survives = (count: number): boolean => count === 2 || count === 3;
31	const isBorn = (count: number): boolean => count === 3;
32	
33	export function nextGeneration(cells: Cell[]): Cell[] {
34	  const liveKeys = new Set(cells.map(cellKey));
35	  const neighborCounts = countLiveNeighbors(cells);
36	
37	  const nextGen: Cell[] = [];
38	  for (const [key, { cell, count }] of neighborCounts) {
39	    const wasAlive = liveKeys.has(key);
40	    if (wasAlive ? survives(count) : isBorn(count)) {
41	      nextGen.push(cell);
42	    }
43	  }
44	  return nextGen;
45	}
